export function FilterItem({ item }: { item: ListItem }) {
  return "path" in item ? (
    <PathFilterItem item={item} />
  ) : (
    <SortFilterItem item={item} />
  );
}

export function isAPIRoute(value?: string) {
  return value === '/api' || Boolean(value?.startsWith('/api/'))
}

if (normalizedPath !== '/') {
  const pathnameEndsWithSlash = normalizedPath.endsWith('/');
  if (trailingSlash && !pathnameEndsWithSlash) {
    normalizedPath += '/';
  } else if (!trailingSlash && pathnameEndsWithSlash) {
    normalizedPath = normalizedPath.slice(0, -1);
  }
}

return (
  key === PAGE_SEGMENT_KEY ||
  key.startsWith(PAGE_SEGMENT_KEY) ||
  key === DEFAULT_SEGMENT_KEY
)

if (!messages) {
  throw new Error(
    process.env.NODE_ENV !== 'production'
      ? `No messages available at \`${namespace}\`.`
      : fullKey
  );
}

if (profileCli) {
  console.log('\x1b[34m=== Next.js CLI Entry Point Profile ===\x1b[0m')
} else {
  console.log('\x1b[34m=== Next.js Dev Server CPU Profile ===\x1b[0m')
  console.log(`Test directory: ${testDir}`)
  console.log(`Bundler: ${useWebpack ? 'Webpack' : 'Turbopack'}`)
}

return {
  lineNumber: line1,
  isErroredLine:
    line1 !== undefined && line1 === stackFrame.line1?.toString(),
}

return memoFn(
    (...args: ConstructorParameters<Fn>) => new ConstructorFn(...args),
    cache
  ) as (...args: ConstructorParameters<Fn>) => InstanceType<Fn>;

if (process.env.NODE_ENV !== 'production' && !(name in values)) {
  throw new Error(`Missing value for argument "${name}"`);
}

if (process.env.NODE_ENV !== 'production' && !branch) {
  throw new Error(
    `No matching branch for select "${name}" with value "${value}"`
  );
}

if (process.env.NODE_ENV !== 'production' && typeof rawValue !== 'number') {
  throw new Error(
    `Expected number for plural argument "${name}", got ${typeof rawValue}`
  );
}

if (process.env.NODE_ENV !== 'production' && !branch) {
  throw new Error(
    `No matching branch for plural "${name}" with category "${category}"`
  );
}

if (process.env.NODE_ENV !== 'production' && typeof rawValue !== 'number') {
  throw new Error(
    `Expected number for argument "${name}", got ${typeof rawValue}`
  );
}
